using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record TicketRequest(string Subject, string Description, int Priority);

public record PredictionResponse(
    string PredictedCategory,
    Dictionary<string, float> Confidence);

public record EvaluationMetrics(
    float MicroAccuracy,
    float MacroAccuracy,
    float LogLoss,
    float LogLossReduction);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext;
    private ITransformer _model = null!;
    private PredictionEngine<TicketData, TicketPrediction> _predictionEngine = null!;
    private EvaluationMetrics _metrics = null!;
    private string[] _categoryLabels = [];

    public EvaluationMetrics Metrics => _metrics;

    public TicketModelService()
    {
        _mlContext = new MLContext(seed: 42);
    }

    public void TrainAndEvaluate(string dataPath)
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Use all data for training since the dataset is very small.
        // With a larger dataset, use TrainTestSplit here.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);

        // Evaluate on the training data to surface available metrics.
        var predictions = _model.Transform(dataView);
        var eval = _mlContext.MulticlassClassification.Evaluate(predictions);
        _metrics = new EvaluationMetrics(
            (float)eval.MicroAccuracy,
            (float)eval.MacroAccuracy,
            (float)eval.LogLoss,
            (float)eval.LogLossReduction);

        // Extract ordered label names so we can map Score[] to categories.
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(dataView.Schema)["Score"]
              .GetSlotNames(ref labelBuffer);
        _categoryLabels = labelBuffer.DenseValues()
            .Select(v => v.ToString()).ToArray();

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse(prediction.PredictedCategory, confidence);
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketModelService modelService) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority is < 1 or > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var prediction = modelService.Predict(request);
        return Ok(prediction);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(modelService.Metrics);
    }
}

